    // =========================================================================
    // Config parsing
    // =========================================================================
    function automatic int cfg_get_int(string key, int default_val = 0);
        for (int i = 0; i < cfg_count; i++) begin
            if (cfg_keys[i] == key) begin
                return cfg_values[i].atoi();
            end
        end
        return default_val;
    endfunction

    function automatic bit cfg_get_bool(string key, bit default_val = 0);
        for (int i = 0; i < cfg_count; i++) begin
            if (cfg_keys[i] == key) begin
                if (cfg_values[i] == "True" || cfg_values[i] == "true" || cfg_values[i] == "1")
                    return 1;
                else
                    return 0;
            end
        end
        return default_val;
    endfunction

    function automatic string cfg_get_str(string key, string default_val = "");
        for (int i = 0; i < cfg_count; i++) begin
            if (cfg_keys[i] == key) return cfg_values[i];
        end
        return default_val;
    endfunction

    // Parse "[1, 2, 3]" style list into int array, return count
    function automatic int cfg_get_list_int(string key, output int arr[64]);
        string raw;
        int cnt = 0;
        raw = cfg_get_str(key, "");
        if (raw.len() == 0) return 0;
        begin
            // Strip brackets and parse comma-separated ints
            automatic string cleaned = "";
            automatic int val = 0;
            automatic bit in_num = 0;
            automatic bit neg = 0;
            for (int i = 0; i < raw.len(); i++) begin
                byte c = raw.getc(i);
                if (c == "-") begin
                    neg = 1;
                end else if (c >= "0" && c <= "9") begin
                    val = val * 10 + (c - "0");
                    in_num = 1;
                end else begin
                    if (in_num) begin
                        arr[cnt] = neg ? -val : val;
                        cnt++;
                        val = 0;
                        in_num = 0;
                        neg = 0;
                    end
                end
            end
            if (in_num) begin
                arr[cnt] = neg ? -val : val;
                cnt++;
            end
        end
        return cnt;
    endfunction

    // =========================================================================
    // Config file reader (key:value per line)
    // =========================================================================
    task automatic load_config(string path);
        int fd;
        string line_str;
        fd = $fopen(path, "r");
        if (fd == 0) begin
            $error("[TB] Cannot open config: %s", path);
            $finish;
        end
        cfg_count = 0;
        while (!$feof(fd)) begin
            automatic string key_s, val_s;
            automatic int colon_pos = -1;
            if ($fgets(line_str, fd) == 0) continue;
            // Trim trailing newline
            while (line_str.len() > 0 && (line_str.getc(line_str.len()-1) == "\n" ||
                                           line_str.getc(line_str.len()-1) == "\r"))
                line_str = line_str.substr(0, line_str.len()-2);
            if (line_str.len() == 0) continue;
            // Find first ':'
            for (int i = 0; i < line_str.len(); i++) begin
                if (line_str.getc(i) == ":") begin
                    colon_pos = i;
                    break;
                end
            end
            if (colon_pos <= 0) continue;
            key_s = line_str.substr(0, colon_pos - 1);
            val_s = line_str.substr(colon_pos + 1, line_str.len() - 1);
            cfg_keys[cfg_count]   = key_s;
            cfg_values[cfg_count] = val_s;
            cfg_count++;
        end
        $fclose(fd);
    endtask

    // =========================================================================
    // Binary file loader (16-bit elements)
    // =========================================================================
    task automatic load_binary_fp16(string path, ref logic [15:0] arr[]);
        int fd;
        int file_size;
        int num_elements;
        byte unsigned byte_buf;
        fd = $fopen(path, "rb");
        if (fd == 0) begin
            $error("[TB] Cannot open binary file: %s", path);
            $finish;
        end
        // Determine file size
        file_size = 0;
        while (!$feof(fd)) begin
            if ($fread(byte_buf, fd) == 0) break;
            file_size++;
        end
        $fclose(fd);
        num_elements = file_size / 2;
        arr = new[num_elements];
        fd = $fopen(path, "rb");
        for (int i = 0; i < num_elements; i++) begin
            automatic byte unsigned lo, hi;
            void'($fread(lo, fd));
            void'($fread(hi, fd));
            arr[i] = {hi, lo}; // little-endian
        end
        $fclose(fd);
    endtask

    // Binary file loader (32-bit elements)
    task automatic load_binary_i32(string path, ref logic [31:0] arr[]);
        int fd;
        int file_size;
        int num_elements;
        byte unsigned byte_buf;
        fd = $fopen(path, "rb");
        if (fd == 0) begin
            $error("[TB] Cannot open binary file: %s", path);
            $finish;
        end
        file_size = 0;
        while (!$feof(fd)) begin
            if ($fread(byte_buf, fd) == 0) break;
            file_size++;
        end
        $fclose(fd);
        num_elements = file_size / 4;
        arr = new[num_elements];
        fd = $fopen(path, "rb");
        for (int i = 0; i < num_elements; i++) begin
            automatic byte unsigned b0, b1, b2, b3;
            void'($fread(b0, fd));
            void'($fread(b1, fd));
            void'($fread(b2, fd));
            void'($fread(b3, fd));
            arr[i] = {b3, b2, b1, b0}; // little-endian
        end
        $fclose(fd);
    endtask

    // =========================================================================
    // FP16 ↔ real conversion helpers
    // =========================================================================
    function automatic real fp16_to_real(logic [15:0] h);
        automatic int sign_bit = h[15];
        automatic int exp_bits = h[14:10];
        automatic int mant_bits = h[9:0];
        automatic real mantissa, result;
        if (exp_bits == 0 && mant_bits == 0) return 0.0;
        if (exp_bits == 5'h1F) begin
            if (mant_bits != 0) return 0.0; // NaN → 0
            return (sign_bit ? -1.0e30 : 1.0e30); // Inf
        end
        if (exp_bits == 0) begin
            // Denormalized
            mantissa = $itor(mant_bits) / 1024.0;
            result = mantissa * (2.0 ** (-14));
        end else begin
            mantissa = 1.0 + $itor(mant_bits) / 1024.0;
            result = mantissa * (2.0 ** (exp_bits - 15));
        end
        return sign_bit ? -result : result;
    endfunction

    // =========================================================================
    // Ceil-division
    // =========================================================================
    function automatic int ceil_div(int a, int b);
        if (b == 0) return 0;
        return (a + b - 1) / b;
    endfunction

    // =========================================================================
    // Wave range helpers (matching ESL get_wave_range / get_wave_tile_range)
    // =========================================================================
    function automatic void get_wave_range(int total, int waves, int wave_idx,
                                           output int w_start, output int w_end);
        automatic int chunk;
        if (waves <= 0) begin w_start = 0; w_end = total; return; end
        chunk = ceil_div(total, waves);
        w_start = wave_idx * chunk;
        if (w_start >= total) begin w_start = total; w_end = total; return; end
        w_end = w_start + chunk;
        if (w_end > total) w_end = total;
    endfunction

    function automatic void get_wave_tile_range(
        int tiles_per_wave[], int tiles_len,
        int wave_idx, int total_tiles, int fallback_waves,
        output int w_start, output int w_end);
        if (tiles_len == 0) begin
            get_wave_range(total_tiles, fallback_waves, wave_idx, w_start, w_end);
            return;
        end
        if (wave_idx < 0 || wave_idx >= tiles_len) begin
            w_start = total_tiles; w_end = total_tiles; return;
        end
        w_start = 0;
        for (int i = 0; i < wave_idx; i++) w_start += tiles_per_wave[i];
        w_end = w_start + tiles_per_wave[wave_idx];
        if (w_start > total_tiles) w_start = total_tiles;
        if (w_end > total_tiles) w_end = total_tiles;
    endfunction

    // =========================================================================
    // Index helpers (matching ESL Index2D, Index3D, Index4D)
    // =========================================================================
    function automatic int idx2d(int d0, int d1, int r, int c);
        // (r, c) in shape [d0][d1]
        return r * d1 + c;
    endfunction

    function automatic int idx3d(int d0, int d1, int d2, int a, int b, int c);
        return (a * d1 + b) * d2 + c;
    endfunction

    function automatic int idx4d(int d0, int d1, int d2, int d3, int a, int b, int c, int d);
        return ((a * d1 + b) * d2 + c) * d3 + d;
    endfunction

    // =========================================================================
    // Meta-FIFO helpers
    // =========================================================================
    function automatic int meta_fifo_num_free();
        return 1024 - ((rx_meta_wr_ptr - rx_meta_rd_ptr + 1024) % 1024);
    endfunction

    task automatic meta_fifo_push(resp_meta_t m);
        rx_meta_fifo[rx_meta_wr_ptr % 1024] = m;
        rx_meta_wr_ptr++;
    endtask

    function automatic bit meta_fifo_try_pop(output resp_meta_t m);
        if (rx_meta_rd_ptr == rx_meta_wr_ptr) return 0;
        m = rx_meta_fifo[rx_meta_rd_ptr % 1024];
        rx_meta_rd_ptr++;
        return 1;
    endfunction

    function automatic int meta_fifo_available();
        return rx_meta_wr_ptr - rx_meta_rd_ptr;
    endfunction

    // =========================================================================
    // Command bus helper (matching ESL send_command)
    // =========================================================================
    task automatic send_command(message_command_t cmd, logic [31:0] param = 0);
        automatic logic [31:0] cmd_data_val;
        cmd_data_val = (param & 32'hFFFFFFF0) | ({28'd0, cmd} & 32'h0000000F);
        command_mode <= 1'b1;
        command_data <= cmd_data_val;
        @(posedge clk);
        command_mode <= 1'b0;
    endtask

    // =========================================================================
    // Valid-ready handshake helpers
    // =========================================================================
    task automatic wait_ready_ps(int timeout = MAX_WAIT_CYCLES * 100);
        automatic int waited = 0;
        while (!noc_ps_in_ready && waited < timeout) begin
            @(posedge clk);
            waited++;
        end
        if (waited >= timeout) begin
            $error("[TB] Timeout waiting ready on noc_ps");
            $finish;
        end
    endtask

    task automatic wait_ready_pd(int timeout = MAX_WAIT_CYCLES * 100);
